import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { firstValueFrom, tap } from 'rxjs';
import { environment } from '../../environments/environment';
import { AuthResponse } from './api.models';
import { Router } from '@angular/router';

export const API_URL = environment.apiUrl;

@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly httpClient = inject(HttpClient);
  private readonly router = inject(Router);

  public async register(nick: string, password: string): Promise<AuthResponse> {
    return firstValueFrom(
      this.httpClient.post<AuthResponse>(`${API_URL}/auth/register`, { nick, password }).pipe(
        tap((res) => {
          localStorage.setItem('token', res.accessToken);
        }),
      ),
    );
  }

  public async login(nick: string, password: string): Promise<AuthResponse> {
    return firstValueFrom(
      this.httpClient.post<AuthResponse>(`${API_URL}/auth/login`, { nick, password }).pipe(
        tap((res) => {
          localStorage.setItem('token', res.accessToken);
        }),
      ),
    );
  }

  public getToken(): string | null {
    return localStorage.getItem('token');
  }

  public logout() {
    localStorage.removeItem('token');
    void this.router.navigate(['/']);
  }
}
